  \node  (v) [below right = 1.5cm of l,xshift=.5cm] {$v$};
  \draw [->] (h) to node [sloped,below] {$ \bar {p} _{ h } $} (u);
  \draw [->] (l) to node [sloped,above] {$ \bar {p} _{ l } $} (u);
