   north = f,
   sw = b,
   se = b,
   south/style = double,
   nw/style = pullback,
 }
  \node  (u') [above left = 1.5cm of nw,xshift=-.5cm] {$ \bar {b}$};
  \node  (u) [above left = 1.5cm of sw,xshift=-.5cm] {$b$};
  \draw [lies over] (u') to (u);
  \draw [double,bend left=30] (u') to (ne);
  \draw [double] (u) to (sw);
  \draw [->,exists] (u') to node [desc] {$g$} (nw);
\end {tikzpicture}

