   south = f,
   se = y,
   nw/style = pullback,
 }
  \node  (u') [above left = 1.5cm of nw,xshift=-.5cm] {$ \bar {x}$};
  \node  (u) [above left = 1.5cm of sw,xshift=-.5cm] {$x$};
  \draw [lies over] (u') to (u);
  \draw [->,bend left=30] (u') to node [sloped,above] {$ \bar {g}$} (ne);
  \draw [double] (u) to (sw);
  \draw [->,exists] (u') to node [desc] {$i$} (nw);
